@Composable
private fun CapacityField(
    theme: MaterialThemePalette,
    label: String,
    capacity: Int?,
    supportingText: String? = null,
    dialogTitle: String,
    dialogSubjectLabel: String,
    onCapacityChange: (Int?) -> Unit,
) {
    var dialogState by remember { mutableStateOf<CapacityDialogState?>(null) }
    val canDecrement = capacity != null && capacity > 1

    fun openDialog(initialDraft: String = capacity?.toString().orEmpty()) {
        dialogState = CapacityDialogState(
            currentCapacity = capacity,
            initialDraft = initialDraft,
        )
    }

    Div({
        style {
            display(DisplayStyle.Flex)
            flexDirection(FlexDirection.Column)
            gap(8.px)
            property("flex", "1")
            property("min-width", "0")
        }
    }) {
        P({
            style {
                margin(0.px)
                property("color", theme.onSurfaceVariant)
                property("font-size", "0.8rem")
                property("font-weight", "700")
                property("letter-spacing", "0.08em")
                property("text-transform", "uppercase")
            }
        }) {
            Text(label)
        }

        Div({
            style {
                display(DisplayStyle.Flex)
                property("align-items", "center")
                gap(10.px)
                property("flex-wrap", "wrap")
            }
        }) {
            CapacityStepButton(
                label = "-",
                theme = theme,
                isDisabled = !canDecrement,
                onClick = {
                    if (capacity != null && capacity > 1) {
                        onCapacityChange(capacity - 1)
                    }
                },
            )

            CapacityDisplayButton(
                label = capacity?.toString() ?: "Unlimited",
                theme = theme,
                onClick = { openDialog() },
            )

            CapacityStepButton(
                label = "+",
                theme = theme,
                isDisabled = false,
                onClick = {
                    if (capacity == null) {
                        onCapacityChange(1)
                    } else {
                        onCapacityChange(capacity + 1)
                    }
                },
            )
        }

        supportingText?.let { hint ->
            P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
                Text(hint)
            }
        }
    }

    dialogState?.let { dialog ->
        CapacitySetDialog(
            currentCapacity = dialog.currentCapacity,
            initialDraft = dialog.initialDraft,
            theme = theme,
            title = dialogTitle,
            subjectLabel = dialogSubjectLabel,
            onCancel = { dialogState = null },
            onApply = { updatedCapacity ->
                onCapacityChange(updatedCapacity)
                dialogState = null
            },
        )
    }
}

@Composable
private fun TicketTierEditor(
    title: String,
    drafts: List<TicketTierDraft>,
    statsByTierId: Map<String, EventTicketTierStatsDto> = emptyMap(),
    theme: MaterialThemePalette,
    onDraftsChange: (List<TicketTierDraft>) -> Unit,
) {
    Div({
        style {
            display(DisplayStyle.Flex)
            flexDirection(FlexDirection.Column)
            gap(14.px)
        }
    }) {
        H4({ style { margin(0.px); property("color", theme.onSurface) } }) {
            Text(title)
        }
        P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
            Text("Define multiple prices here. Use the tier capacity control for small changes, or tap the value to set an exact cap or switch to Unlimited. Inactive tiers stay available for history but stop new issuance.")
        }

        drafts.forEachIndexed { index, draft ->
            val ticketTierStats = draft.id?.let { statsByTierId[it] }
            Div({
                style {
                    padding(18.px)
                    borderRadius(24.px)
                    property("border", "1px solid ${theme.outlineVariant}")
                    property("background-color", theme.surface)
                    display(DisplayStyle.Flex)
                    flexDirection(FlexDirection.Column)
                    gap(14.px)
                }
            }) {
                Div({
                    style {
                        display(DisplayStyle.Flex)
                        property("justify-content", "space-between")
                        property("align-items", "center")
                        property("gap", "10px")
                        property("flex-wrap", "wrap")
                    }
                }) {
                    H4({ style { margin(0.px); property("color", theme.onSurface) } }) {
                        Text("Tier ${index + 1}")
                    }
                    Div({
                        style {
                            display(DisplayStyle.Flex)
                            gap(8.px)
                            property("flex-wrap", "wrap")
                        }
                    }) {
                        ChoiceChip(
                            label = if (draft.active) "Active" else "Inactive",
                            isSelected = draft.active,
                            onClick = {
                                onDraftsChange(
                                    drafts.updateAt(index) { existing -> existing.copy(active = !existing.active) }
                                )
                            },
                            theme = theme,
                        )
                        ActionButton(
                            label = if (draft.id == null) "Remove Tier" else "Archive in Form",
                            onClick = {
                                onDraftsChange(
                                    if (draft.id == null && drafts.size > 1) {
                                        drafts.filterIndexed { currentIndex, _ -> currentIndex != index }
                                    } else {
                                        drafts.updateAt(index) { existing -> existing.copy(active = false) }
                                    }
                                )
                            },
                            theme = theme,
                            isPrimary = false,
                            isDisabled = drafts.size == 1 && draft.id == null,
                        )
                    }
                }

                FieldRow {
                    TextField(
                        theme = theme,
                        label = "Tier Name",
                        value = draft.name,
                        onValueChange = { value ->
                            onDraftsChange(drafts.updateAt(index) { existing -> existing.copy(name = value) })
                        },
                        placeholder = "General Admission",
                    )
                    TextField(
                        theme = theme,
                        label = "Price",
                        value = draft.priceInput,
                        onValueChange = { value ->
                            onDraftsChange(drafts.updateAt(index) { existing -> existing.copy(priceInput = value) })
                        },
                        placeholder = "5.00",
                    )
                    CapacityField(
                        theme = theme,
                        label = "Tier Capacity",
                        capacity = parseCapacityInput(draft.capacityInput),
                        dialogTitle = "Set Tier Capacity",
                        dialogSubjectLabel = "tier",
                        onCapacityChange = { updatedCapacity ->
                            onDraftsChange(
                                drafts.updateAt(index) { existing ->
                                    existing.copy(capacityInput = formatCapacityInput(updatedCapacity))
                                }
                            )
                        },
                    )
                }

                ticketTierStats?.let { tierStats ->
                    Div({
                        style {
                            display(DisplayStyle.Flex)
                            gap(10.px)
                            property("flex-wrap", "wrap")
                        }
                    }) {
                        StatPill(label = "Sold", value = tierStats.soldCount.toString(), theme = theme)
                        StatPill(label = "Remaining", value = tierStats.remainingCount?.toString() ?: "Unlimited", theme = theme)
                    }
                    if (tierStats.capacity != null && tierStats.remainingCount == 0) {
                        StatusBanner(
                            message = "${tierStats.ticketTierName} tier is sold out.",
                            tone = BannerTone.Info,
                            theme = theme,
                        )
                    }
                }

                Div({
                    style {
                        display(DisplayStyle.Flex)
                        flexDirection(FlexDirection.Column)
                        gap(10.px)
                    }
                }) {
                    P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
                        Text("Entitlements")
                    }
                    if (draft.entitlements.isEmpty()) {
                        P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
                            Text("No entitlements on this tier yet.")
                        }
                    } else {
                        draft.entitlements.forEachIndexed { entitlementIndex, entitlementDraft ->
                            EntitlementEditor(
                                draft = entitlementDraft,
                                theme = theme,
                                onChange = { updatedEntitlement ->
                                    onDraftsChange(
                                        drafts.updateAt(index) { currentTier ->
                                            currentTier.copy(
                                                entitlements = currentTier.entitlements.updateAt(entitlementIndex) { updatedEntitlement }
                                            )
                                        }
                                    )
                                },
                                onRemove = {
                                    onDraftsChange(
                                        drafts.updateAt(index) { currentTier ->
                                            currentTier.copy(
                                                entitlements = currentTier.entitlements.filterIndexed { currentEntitlementIndex, _ ->
                                                    currentEntitlementIndex != entitlementIndex
                                                }
                                            )
                                        }
                                    )
                                },
                            )
                        }
                    }
                    ActionButton(
                        label = "Add Entitlement",
                        onClick = {
                            onDraftsChange(
                                drafts.updateAt(index) { currentTier ->
                                    currentTier.copy(entitlements = currentTier.entitlements + TicketEntitlementDraft())
                                }
                            )
                        },
                        isPrimary = false,
                        theme = theme,
                    )
                }
            }
        }

        ActionButton(
            label = "Add Ticket Tier",
            onClick = { onDraftsChange(drafts + defaultTicketTierDraft()) },
            isPrimary = false,
            theme = theme,
        )
    }
}

@Composable
private fun CapacityStepButton(
    label: String,
    theme: MaterialThemePalette,
    isDisabled: Boolean,
    onClick: () -> Unit,
) {
    var isPressed by remember(isDisabled) { mutableStateOf(false) }

    Button(
        attrs = {
            if (isDisabled) disabled()
            onClick { onClick() }
            onMouseDown { if (!isDisabled) isPressed = true }
            onMouseUp { isPressed = false }
            onMouseLeave { isPressed = false }
            onTouchStart { if (!isDisabled) isPressed = true }
            onTouchEnd { isPressed = false }
            onTouchCancel { isPressed = false }
            onBlur { isPressed = false }
            style {
                padding(0.px)
                property("width", "44px")
                property("height", "44px")
                property("border-radius", "999px")
                property("border", "1px solid ${theme.outline}")
                property("background-color", theme.surfaceContainerHighest)
                property("color", theme.onSurface)
                property("font-size", "1.2rem")
                property("font-weight", "700")
                property(
                    "box-shadow",
                    if (isPressed && !isDisabled) {
                        "0 2px 8px ${theme.shadow}"
                    } else {
                        "0 8px 18px ${theme.shadow}"
                    }
                )
                property(
                    "transform",
                    if (isPressed && !isDisabled) "translateY(1px)" else "translateY(0)"
                )
                property("transition", "transform 120ms ease, box-shadow 120ms ease, opacity 120ms ease")
                property("cursor", if (isDisabled) "default" else "pointer")
                property("touch-action", "manipulation")
                property("user-select", "none")
                property("-webkit-tap-highlight-color", "transparent")
                if (isDisabled) {
                    property("opacity", "0.5")
                }
            }
        }
    ) {
        Text(label)
    }
}

