@Composable
private fun CapacitySetDialog(
    currentCapacity: Int?,
    initialDraft: String,
    theme: MaterialThemePalette,
    title: String,
    subjectLabel: String,
    onCancel: () -> Unit,
    onApply: (Int?) -> Unit,
) {
    var capacityDraft by remember(initialDraft) { mutableStateOf(initialDraft) }
    var dialogError by remember(initialDraft) { mutableStateOf<String?>(null) }

    Div(
        attrs = {
            style {
                property("position", "fixed")
                property("inset", "0")
                property("display", "flex")
                property("align-items", "center")
                property("justify-content", "center")
                property("padding", "24px")
                property("background", "rgba(15, 23, 42, 0.24)")
                property("backdrop-filter", "blur(10px)")
                property("z-index", "1100")
            }
            onClick { onCancel() }
        }
    ) {
        Div(
            attrs = {
                onClick { it.stopPropagation() }
                style {
                    property("width", "min(100%, 420px)")
                    property("display", "flex")
                    property("flex-direction", "column")
                    property("gap", "16px")
                    padding(22.px)
                    borderRadius(28.px)
                    property(
                        "background",
                        "linear-gradient(180deg, ${theme.surfaceContainerHighest} 0%, ${theme.surface} 100%)"
                    )
                    property("border", "1px solid ${theme.outlineVariant}")
                    property("box-shadow", "0 24px 60px ${theme.shadow}, inset 0 1px 0 ${theme.scrim}")
                }
            }
        ) {
            H3({
                style {
                    margin(0.px)
                    property("font-family", "\"SF Pro Display\", \"Avenir Next\", sans-serif")
                    property("font-size", "1.4rem")
                    property("letter-spacing", "-0.03em")
                }
            }) {
                Text(title)
            }

            P({
                style {
                    margin(0.px)
                    property("color", theme.onSurfaceVariant)
                    property("line-height", "1.5")
                }
            }) {
                Text(
                    if (currentCapacity == null) {
                        "This $subjectLabel is currently Unlimited. Choose Unlimited again or set an exact cap."
                    } else {
                        "This $subjectLabel is currently capped at $currentCapacity tickets. Choose Unlimited or set a new exact cap."
                    }
                )
            }

            dialogError?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Error,
                )
            }

            TextField(
                theme = theme,
                label = "Exact Capacity",
                value = capacityDraft,
                onValueChange = {
                    capacityDraft = it
                    dialogError = null
                },
                placeholder = "Enter a whole number",
                inputTypeOverride = "number",
            )

            Div({
                style {
                    property("display", "flex")
                    property("justify-content", "flex-end")
                    property("gap", "10px")
                    property("flex-wrap", "wrap")
                }
            }) {
                ActionButton(
                    label = "Cancel",
                    onClick = onCancel,
                    theme = theme,
                    isPrimary = false,
                )
                ActionButton(
                    label = "Use Unlimited",
                    onClick = { onApply(null) },
                    theme = theme,
                    isPrimary = false,
                )
                ActionButton(
                    label = "Apply Amount",
                    onClick = {
                        val parsedCapacity = capacityDraft.trim().toIntOrNull()
                        when {
                            parsedCapacity == null -> dialogError = "Enter a whole number capacity or choose Unlimited."
                            parsedCapacity < 1 -> dialogError = "Capacity must be at least 1. Use Unlimited if you do not want a cap."
                            else -> onApply(parsedCapacity)
                        }
                    },
                    theme = theme,
                )
            }
        }
    }
}

