            }

            Div(
                attrs = {
                    style {
                        display(DisplayStyle.Flex)
                        property("justify-content", "flex-end")
                        gap(12.px)
                        property("margin-top", "8px")
                    }
                }
            ) {
                ActionButton(
                    label = "Close",
                    onClick = onClose,
                    theme = theme,
                    isPrimary = false,
                )
                ActionButton(
                    label = "Go to Inventory",
                    onClick = {
                        onClose()
                        onNavigateToInventory()
                    },
                    theme = theme,
                    isPrimary = true,
                )
            }
        }
    }
}
