package com.kanati.shared.report

import kotlinx.serialization.Serializable

@Serializable
data class DailySalesReportRow(
    val date: String,
    val subtotalAmount: Long,
    val taxAmount: Long,
    val totalAmount: Long,
)

@Serializable
data class TopProductReportRow(
    val productId: String,
    val productName: String,
    val unitsSold: Long,
    val grossSalesAmount: Long,
)

@Serializable
data class InventoryReportRow(
    val productId: String,
    val productName: String,
    val quantityOnHand: Int,
    val updatedAt: String?,
)
