    prettyPrint = true
    explicitNulls = false
}

private data class ThemeFieldSpec(
    val key: String,
    val label: String,
    val placeholder: String,
)

private data class ConsumerRuntimePreviewModel(
    val eyebrow: String,
    val title: String,
    val body: String,
    val buttons: List<String>,
)

private val commonThemeFields = listOf(
    ThemeFieldSpec("primary", "Primary", "#0B5FFF"),
    ThemeFieldSpec("onPrimary", "On Primary", "#FFFFFF"),
    ThemeFieldSpec("secondary", "Secondary", "#3BB273"),
    ThemeFieldSpec("onSecondary", "On Secondary", "#0C1B14"),
    ThemeFieldSpec("background", "Background", "#F5F7FB"),
    ThemeFieldSpec("onBackground", "On Background", "#102033"),
    ThemeFieldSpec("surface", "Surface", "#FFFFFF"),
    ThemeFieldSpec("onSurface", "On Surface", "#122033"),
    ThemeFieldSpec("surfaceVariant", "Surface Variant", "#DCE7F5"),
    ThemeFieldSpec("onSurfaceVariant", "On Surface Variant", "#50627A"),
    ThemeFieldSpec("outline", "Outline", "#9EB0C6"),
    ThemeFieldSpec("logoUrl", "Logo URL", "https://example.com/logo.png"),
)

@Composable
fun SettingsScreen(
    apiClient: AdminApiClient,
    district: SelectedDistrictContext?,
    districtLoading: Boolean,
    districtLoadError: String?,
    theme: MaterialThemePalette,
    onDistrictTaxRateUpdated: (Int) -> Unit,
    canEdit: Boolean,
) {
    val scope = rememberCoroutineScope()
    val selectedDistrict = district
    var settings by remember { mutableStateOf<DistrictSettingsResponse?>(null) }
    var draftTaxRate by remember { mutableStateOf("") }
    var draftConsumerThemeJson by remember { mutableStateOf("") }
    var draftHomeDocumentJson by remember { mutableStateOf("") }
    var isLoading by remember { mutableStateOf(false) }
    var isSaving by remember { mutableStateOf(false) }
    var loadError by remember { mutableStateOf<String?>(null) }
    var taxSaveError by remember { mutableStateOf<String?>(null) }
    var taxSaveMessage by remember { mutableStateOf<String?>(null) }
    var runtimeSaveError by remember { mutableStateOf<String?>(null) }
    var runtimeSaveMessage by remember { mutableStateOf<String?>(null) }
    val parsedThemeObject = remember(draftConsumerThemeJson) { parseJsonObjectOrNull(draftConsumerThemeJson) }
    val themeJsonError = remember(draftConsumerThemeJson) { jsonObjectError(draftConsumerThemeJson) }
    val homeDocumentError = remember(draftHomeDocumentJson) { jsonObjectError(draftHomeDocumentJson) }
    val previewModel = remember(draftHomeDocumentJson) { buildConsumerRuntimePreviewModel(draftHomeDocumentJson) }

    fun settingsUnavailableMessage(): String =
        when {
            districtLoading -> "Loading district context..."
            districtLoadError != null -> "District context could not be loaded. Refresh context and select a district to manage settings."
            else -> "Select a district to manage district settings."
        }

    suspend fun loadSettings(currentDistrict: SelectedDistrictContext) {
        isLoading = true
        loadError = null
        try {
            val response = apiClient.getDistrictSettings(currentDistrict.id)
            settings = response
            draftTaxRate = formatTaxRateInput(response.defaultTaxRateBps)
            draftConsumerThemeJson = response.consumerApp?.nativeUiThemeJson.orEmpty()
            draftHomeDocumentJson = response.consumerApp?.homeDocumentJson.orEmpty()
        } catch (exception: Exception) {
            loadError = exception.message ?: "Unable to load district settings."
        } finally {
            isLoading = false
        }
    }

    LaunchedEffect(selectedDistrict?.id, districtLoading, districtLoadError) {
        taxSaveError = null
        taxSaveMessage = null
        runtimeSaveError = null
        runtimeSaveMessage = null

        if (selectedDistrict == null) {
            settings = null
            draftTaxRate = ""
            draftConsumerThemeJson = ""
            draftHomeDocumentJson = ""
            loadError = settingsUnavailableMessage()
            return@LaunchedEffect
        }

        loadSettings(selectedDistrict)
    }

    SectionCard(
        title = "District Settings",
        theme = theme,
        description = "Review district-wide defaults for the currently selected district.",
    ) {
        if (selectedDistrict == null) {
            StatusBanner(
                message = settingsUnavailableMessage(),
                theme = theme,
                tone = if (districtLoadError != null) BannerTone.Error else BannerTone.Info,
            )
        } else {
            if (!canEdit) {
                StatusBanner(
                    message = "Read-only access. District setting changes require district edit permission.",
                    theme = theme,
                )
            }
            SettingsSummaryPanel(
                district = selectedDistrict,
                effectiveTaxRateBps = settings?.defaultTaxRateBps ?: selectedDistrict.defaultTaxRateBps ?: 0,
                hasConsumerRuntimeSettings = settings?.consumerApp != null,
                theme = theme,
            )
        }
    }

    if (selectedDistrict != null) {
        SectionCard(
            title = "Sales Tax",
            theme = theme,
            description = "Taxable products use this district default sales tax rate. Tax-exempt products always use zero tax.",
            headerActions = {
                ActionButton(
                    label = if (isLoading) "Loading..." else "Reload",
                    onClick = {
                        scope.launch {
                            loadSettings(selectedDistrict)
                        }
                    },
                    theme = theme,
                    isPrimary = false,
                    isDisabled = isLoading || isSaving || !canEdit,
                )
            },
        ) {
            loadError?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Error,
                )
            }

            taxSaveError?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Error,
                )
            }

            taxSaveMessage?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Success,
                )
            }

            settings?.taxRules?.takeIf { it.isNotEmpty() }?.let { taxRules ->
                Div(
                    attrs = {
                        style {
                            display(DisplayStyle.Flex)
                            flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                            gap(10.px)
                            padding(16.px)
                            borderRadius(22.px)
                            property(
                                "background",
                                "linear-gradient(180deg, ${theme.surfaceContainerHighest} 0%, ${theme.surfaceVariant} 100%)"
                            )
                            property("border", "1px solid ${theme.outlineVariant}")
                            property("box-shadow", "inset 0 1px 0 ${theme.scrim}")
                        }
                    }
                ) {
                    P(
                        attrs = {
                            style {
                                margin(0.px)
                                property("font-size", "0.8rem")
                                property("font-weight", "700")
                                property("letter-spacing", "0.08em")
                                property("text-transform", "uppercase")
                                property("color", theme.onSurfaceVariant)
                            }
                        }
                    ) {
                        Text("Returned Tax Rules")
                    }

                    taxRules.forEach { taxRule ->
                        P(
                            attrs = {
                                style {
                                    margin(0.px)
                                    property("color", theme.onSurfaceVariant)
                                    property("font-size", "0.92rem")
                                    property("line-height", "1.5")
                                }
                            }
                        ) {
                            Text("${taxRule.name}: ${formatTaxRatePercent(taxRule.rateBps)}")
                        }
                    }
                }
            }

            TextField(
                theme = theme,
                label = "Default Sales Tax Rate",
                value = draftTaxRate,
                placeholder = "7.25",
                onValueChange = {
                    if (canEdit) {
                        draftTaxRate = it
                        taxSaveError = null
                        taxSaveMessage = null
                    }
                },
            )

            P(
                attrs = {
                    style {
                        margin(0.px)
                        property("color", theme.onSurfaceVariant)
                        property("font-size", "0.9rem")
                        property("line-height", "1.5")
                    }
                }
            ) {
                Text("Enter a percentage such as 7.25. Kanati stores this as basis points and applies it only to products marked Taxable.")
            }

            ActionButton(
                label = if (isSaving) "Saving..." else "Save Sales Tax",
                onClick = {
                    if (!canEdit) return@ActionButton
                    val basisPoints = parseTaxRateInputToBps(draftTaxRate)
                    when {
                        basisPoints == null -> taxSaveError = "Enter a valid sales tax rate such as 7.25."
                        basisPoints !in 0..10_000 -> taxSaveError = "Enter a sales tax rate between 0 and 100."
                        else -> scope.launch {
                            isSaving = true
                            taxSaveError = null
                            taxSaveMessage = null
                            try {
                                val updated = apiClient.updateDistrictSettings(
                                    districtId = selectedDistrict.id,
                                    request = UpdateDistrictSettingsRequest(
                                        defaultTaxRateBps = basisPoints,
                                        consumerApp = settings?.consumerApp,
                                    )
                                )
                                settings = updated
                                draftTaxRate = formatTaxRateInput(updated.defaultTaxRateBps)
                                onDistrictTaxRateUpdated(updated.defaultTaxRateBps)
                                taxSaveMessage = "Saved. Taxable products in ${selectedDistrict.name} now use ${formatTaxRatePercent(updated.defaultTaxRateBps)}."
                            } catch (exception: Exception) {
                                taxSaveError = exception.message ?: "Unable to save district settings."
                            } finally {
                                isSaving = false
                            }
                        }
                    }
                },
                theme = theme,
                isDisabled = isLoading || isSaving || !canEdit,
            )
        }

        SectionCard(
            title = "Consumer Runtime",
            theme = theme,
            description = "Store optional NativeUI theme JSON and a NativeUI home document JSON for consumer apps in this district.",
            headerActions = {
                ActionButton(
                    label = if (isLoading) "Loading..." else "Reload",
                    onClick = {
                        scope.launch {
                            loadSettings(selectedDistrict)
                        }
                    },
                    theme = theme,
                    isPrimary = false,
                    isDisabled = isLoading || isSaving || !canEdit,
                )
            },
        ) {
            loadError?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Error,
                )
            }

            runtimeSaveError?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Error,
                )
            }

            runtimeSaveMessage?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Success,
                )
            }

            themeJsonError?.let {
                StatusBanner(
                    message = "Theme JSON preview is unavailable: $it",
                    theme = theme,
                    tone = BannerTone.Info,
                )
            }

            homeDocumentError?.let {
                StatusBanner(
                    message = "Home document preview is unavailable: $it",
                    theme = theme,
                    tone = BannerTone.Info,
                )
            }

            Div(
                attrs = {
                    style {
                        display(DisplayStyle.Flex)
                        flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                        gap(18.px)
                    }
                }
            ) {
                P(
                    attrs = {
                        style {
                            margin(0.px)
                            property("color", theme.onSurfaceVariant)
                            property("font-size", "0.9rem")
                            property("line-height", "1.55")
                        }
                    }
                ) {
                    Text("Use the structured theme fields for the most common NativeUI roles. The raw JSON editors below stay available for advanced roles and full document control.")
                }

                commonThemeFields.chunked(2).forEach { fieldRow ->
                    FieldRow {
                        fieldRow.forEach { field ->
                            ThemeDraftField(
                                field = field,
                                currentValue = parsedThemeObject.themeValue(field.key),
                                theme = theme,
                                onValueChange = { nextValue ->
                                    if (canEdit) {
                                        draftConsumerThemeJson = updateThemeJsonField(
                                            currentJson = draftConsumerThemeJson,
                                            key = field.key,
                                            value = nextValue,
                                        )
                                        runtimeSaveError = null
                                        runtimeSaveMessage = null
                                    }
                                },
                            )
                        }
                    }
                }
            }

            TextAreaField(
                theme = theme,
                label = "Advanced Theme JSON",
                value = draftConsumerThemeJson,
                placeholder = """{"primary":"#0B5FFF","onPrimary":"#FFFFFF"}""",
                rows = 8,
                onValueChange = {
                    if (canEdit) {
                        draftConsumerThemeJson = it
                        runtimeSaveError = null
                        runtimeSaveMessage = null
                    }
                },
            )

            TextAreaField(
                theme = theme,
                label = "Home Document JSON",
                value = draftHomeDocumentJson,
                placeholder = """{"id":"selu-home","version":"1.0","rootPageId":"home","pages":[{"id":"home","blocks":[]}]}""",
                rows = 14,
                onValueChange = {
                    if (canEdit) {
                        draftHomeDocumentJson = it
                        runtimeSaveError = null
                        runtimeSaveMessage = null
                    }
                },
            )

            P(
                attrs = {
                    style {
                        margin(0.px)
                        property("color", theme.onSurfaceVariant)
                        property("font-size", "0.9rem")
                        property("line-height", "1.55")
                    }
                }
            ) {
                Text("Leave either field blank to fall back to bundled app defaults. Theme JSON should match NativeUI theme role names, and the home document should be a full NativeUI document object.")
            }

            ConsumerRuntimePreviewCard(
                theme = theme,
                previewTheme = resolvedPreviewTheme(
                    adminTheme = theme,
                    themeObject = parsedThemeObject,
                ),
                preview = previewModel,
                themeJsonError = themeJsonError,
                homeDocumentError = homeDocumentError,
            )

            ActionButton(
                label = if (isSaving) "Saving..." else "Save Consumer Runtime",
                onClick = {
                    if (!canEdit) return@ActionButton
                    scope.launch {
                        isSaving = true
                        runtimeSaveError = null
                        runtimeSaveMessage = null
                        try {
                            val updated = apiClient.updateDistrictSettings(
                                districtId = selectedDistrict.id,
                                request = UpdateDistrictSettingsRequest(
                                    defaultTaxRateBps = settings?.defaultTaxRateBps
                                        ?: selectedDistrict.defaultTaxRateBps
                                        ?: 0,
                                    consumerApp = ConsumerAppRuntimeSettings(
                                        nativeUiThemeJson = draftConsumerThemeJson.trim().ifBlank { null },
                                        homeDocumentJson = draftHomeDocumentJson.trim().ifBlank { null },
                                    ).takeIf {
                                        it.nativeUiThemeJson != null || it.homeDocumentJson != null
                                    },
                                )
                            )
                            settings = updated
                            draftConsumerThemeJson = updated.consumerApp?.nativeUiThemeJson.orEmpty()
                            draftHomeDocumentJson = updated.consumerApp?.homeDocumentJson.orEmpty()
                            runtimeSaveMessage = "Saved. Consumer apps in ${selectedDistrict.name} will use the updated runtime NativeUI settings on their next refresh."
                        } catch (exception: Exception) {
                            runtimeSaveError = exception.message ?: "Unable to save consumer runtime settings."
                        } finally {
                            isSaving = false
                        }
                    }
                },
                theme = theme,
                isDisabled = isLoading || isSaving || !canEdit,
            )
        }
    }
}

@Composable
private fun ThemeDraftField(
    field: ThemeFieldSpec,
    currentValue: String,
    theme: MaterialThemePalette,
    onValueChange: (String) -> Unit,
) {
    TextField(
        theme = theme,
        label = field.label,
        value = currentValue,
        placeholder = field.placeholder,
        onValueChange = onValueChange,
    )
}

@Composable
private fun ConsumerRuntimePreviewCard(
    theme: MaterialThemePalette,
    previewTheme: PreviewThemePalette,
    preview: ConsumerRuntimePreviewModel,
    themeJsonError: String?,
    homeDocumentError: String?,
) {
    Div(
        attrs = {
            style {
                display(DisplayStyle.Flex)
                flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                gap(16.px)
                padding(18.px)
                borderRadius(24.px)
                property(
                    "background",
                    "linear-gradient(180deg, ${theme.surfaceContainerHighest} 0%, ${theme.surfaceVariant} 100%)"
                )
                property("border", "1px solid ${theme.outlineVariant}")
                property("box-shadow", "0 16px 32px ${theme.shadow}, inset 0 1px 0 ${theme.scrim}")
            }
        }
    ) {
        P(
            attrs = {
                style {
                    margin(0.px)
                    property("font-size", "0.8rem")
                    property("font-weight", "700")
                    property("letter-spacing", "0.08em")
                    property("text-transform", "uppercase")
                    property("color", theme.onSurfaceVariant)
                }
            }
        ) {
            Text("Live Preview")
        }

        FieldRow {
            PreviewSwatch("Primary", previewTheme.primary, previewTheme.onPrimary, theme)
            PreviewSwatch("Surface", previewTheme.surface, previewTheme.onSurface, theme)
            PreviewSwatch("Background", previewTheme.background, previewTheme.onBackground, theme)
        }

        Div(
            attrs = {
                style {
                    padding(20.px)
                    borderRadius(24.px)
                    property("background", previewTheme.background)
                    property("color", previewTheme.onBackground)
                    property("border", "1px solid ${previewTheme.outline}")
                    property("box-shadow", "inset 0 1px 0 rgba(255,255,255,0.24)")
                }
            }
        ) {
            Div(
                attrs = {
                    style {
                        display(DisplayStyle.Flex)
                        property("justify-content", "space-between")
                        property("align-items", "center")
                        gap(12.px)
                    }
                }
            ) {
                Div {
                    P(
                        attrs = {
                            style {
                                margin(0.px)
                                property("font-size", "0.78rem")
                                property("font-weight", "700")
                                property("letter-spacing", "0.08em")
                                property("text-transform", "uppercase")
                                property("color", previewTheme.primary)
                            }
                        }
                    ) {
                        Text(preview.eyebrow)
                    }
                    P(
                        attrs = {
                            style {
                                margin(0.px)
                                property("font-size", "1.35rem")
                                property("font-weight", "700")
                                property("color", previewTheme.onBackground)
                            }
                        }
                    ) {
                        Text(preview.title)
                    }
                }
                previewTheme.logoUrl?.let { logoUrl ->
                    Div(
                        attrs = {
                            style {
                                padding(8.px, 12.px)
                                borderRadius(999.px)
                                property("background", previewTheme.surfaceVariant)
                                property("color", previewTheme.onSurfaceVariant)
                                property("font-size", "0.78rem")
                                property("font-weight", "600")
                                property("max-width", "240px")
                                property("overflow", "hidden")
                                property("text-overflow", "ellipsis")
                                property("white-space", "nowrap")
                            }
                        }
                    ) {
                        Text("Logo: $logoUrl")
                    }
                }
            }

            Div(
                attrs = {
                    style {
                        property("margin-top", "16px")
                        padding(18.px)
                        borderRadius(22.px)
                        property("background", previewTheme.surface)
                        property("color", previewTheme.onSurface)
                        property("border", "1px solid ${previewTheme.outline}")
                    }
                }
            ) {
                P(
                    attrs = {
                        style {
                            margin(0.px)
                            property("font-size", "1.1rem")
                            property("font-weight", "700")
                        }
                    }
                ) {
                    Text(preview.title)
                }
                P(
                    attrs = {
                        style {
                            property("margin-top", "10px")
                            margin(0.px)
                            property("font-size", "0.96rem")
                            property("line-height", "1.6")
                            property("color", previewTheme.onSurfaceVariant)
                        }
                    }
                ) {
                    Text(preview.body)
                }
                Div(
                    attrs = {
                        style {
                            display(DisplayStyle.Flex)
                            gap(10.px)
                            property("flex-wrap", "wrap")
                            property("margin-top", "16px")
                        }
                    }
                ) {
                    preview.buttons.forEachIndexed { index, label ->
                        Div(
                            attrs = {
                                style {
                                    padding(12.px, 16.px)
                                    borderRadius(14.px)
                                    property(
                                        "background",
                                        if (index == 0) previewTheme.primary else previewTheme.surfaceVariant
                                    )
                                    property(
                                        "color",
                                        if (index == 0) previewTheme.onPrimary else previewTheme.onSurface
                                    )
                                    property(
                                        "border",
                                        if (index == 0) {
                                            "1px solid ${previewTheme.primary}"
                                        } else {
                                            "1px solid ${previewTheme.outline}"
                                        }
                                    )
                                    property("font-size", "0.92rem")
                                    property("font-weight", "700")
                                }
                            }
                        ) {
                            Text(label)
                        }
                    }
                }
            }
        }

        if (themeJsonError == null && homeDocumentError == null) {
            P(
                attrs = {
                    style {
                        margin(0.px)
                        property("font-size", "0.88rem")
                        property("color", theme.onSurfaceVariant)
                        property("line-height", "1.5")
                    }
                }
            ) {
                Text("Preview updates from the current draft. Invalid color tokens fall back to the admin palette in this preview, while the saved JSON remains unchanged until you save.")
            }
        }
    }
}

@Composable
private fun PreviewSwatch(
    label: String,
    background: String,
    foreground: String,
    theme: MaterialThemePalette,
) {
    Div(
        attrs = {
            style {
                flex(1)
                property("min-width", "140px")
                padding(14.px)
                borderRadius(18.px)
                property("background", background)
                property("color", foreground)
                property("border", "1px solid ${theme.outlineVariant}")
            }
        }
    ) {
        P(
            attrs = {
                style {
                    margin(0.px)
                    property("font-size", "0.74rem")
                    property("font-weight", "700")
                    property("letter-spacing", "0.08em")
                    property("text-transform", "uppercase")
                }
            }
        ) {
            Text(label)
        }
        P(
            attrs = {
                style {
                    property("margin-top", "8px")
                    margin(0.px)
                    property("font-size", "0.86rem")
                    property("font-family", "'SFMono-Regular', 'JetBrains Mono', monospace")
                }
            }
        ) {
            Text(background)
        }
    }
}

@Composable
private fun SettingsSummaryPanel(
    district: SelectedDistrictContext,
    effectiveTaxRateBps: Int,
    hasConsumerRuntimeSettings: Boolean,
    theme: MaterialThemePalette,
) {
    Div(
        attrs = {
            style {
                display(DisplayStyle.Flex)
                gap(14.px)
                property("flex-wrap", "wrap")
            }
        }
    ) {
        SettingsFact(
            label = "District",
            value = district.name,
            theme = theme,
        )
        SettingsFact(
            label = "Timezone",
            value = district.timezone ?: "Not set",
            theme = theme,
        )
        SettingsFact(
            label = "Default Sales Tax",
            value = formatTaxRatePercent(effectiveTaxRateBps),
            theme = theme,
        )
        SettingsFact(
            label = "Consumer Runtime",
            value = if (hasConsumerRuntimeSettings) "Configured" else "Bundled Defaults",
            theme = theme,
        )
    }
}

@Composable
private fun SettingsFact(
    label: String,
    value: String,
    theme: MaterialThemePalette,
) {
    Div(
        attrs = {
            style {
                display(DisplayStyle.Flex)
                flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                gap(6.px)
                padding(16.px)
                borderRadius(22.px)
                flex(1)
                property("min-width", "180px")
                property(
                    "background",
                    "linear-gradient(180deg, ${theme.surfaceContainerHighest} 0%, ${theme.surfaceVariant} 100%)"
                )
                property("border", "1px solid ${theme.outlineVariant}")
                property("box-shadow", "inset 0 1px 0 ${theme.scrim}")
            }
        }
    ) {
        P(
            attrs = {
                style {
                    margin(0.px)
                    property("font-size", "0.78rem")
                    property("font-weight", "700")
                    property("letter-spacing", "0.08em")
                    property("text-transform", "uppercase")
                    property("color", theme.onSurfaceVariant)
                }
            }
        ) {
            Text(label)
        }

        P(
            attrs = {
                style {
                    margin(0.px)
                    property("font-size", "1rem")
                    property("font-weight", "650")
                    property("color", theme.onSurface)
                    property("line-height", "1.4")
                }
            }
        ) {
            Text(value)
        }
    }
}

private data class PreviewThemePalette(
    val primary: String,
    val onPrimary: String,
    val background: String,
    val onBackground: String,
    val surface: String,
    val onSurface: String,
    val surfaceVariant: String,
    val onSurfaceVariant: String,
    val outline: String,
    val logoUrl: String?,
)

private fun resolvedPreviewTheme(
    adminTheme: MaterialThemePalette,
    themeObject: JsonObject?,
): PreviewThemePalette =
    PreviewThemePalette(
        primary = themeObject.cssColor("primary") ?: adminTheme.primary,
        onPrimary = themeObject.cssColor("onPrimary") ?: adminTheme.onPrimary,
        background = themeObject.cssColor("background") ?: adminTheme.surface,
        onBackground = themeObject.cssColor("onBackground") ?: adminTheme.onSurface,
        surface = themeObject.cssColor("surface") ?: adminTheme.surfaceContainerHighest,
        onSurface = themeObject.cssColor("onSurface") ?: adminTheme.onSurface,
        surfaceVariant = themeObject.cssColor("surfaceVariant") ?: adminTheme.surfaceVariant,
        onSurfaceVariant = themeObject.cssColor("onSurfaceVariant") ?: adminTheme.onSurfaceVariant,
        outline = themeObject.cssColor("outline") ?: adminTheme.outline,
        logoUrl = themeObject.themeValue("logoUrl").ifBlank { null },
    )

private fun parseJsonObjectOrNull(rawJson: String): JsonObject? {
    val candidate = rawJson.trim().ifBlank { return null }
    return runCatching { runtimeJson.parseToJsonElement(candidate).jsonObject }.getOrNull()
}

private fun jsonObjectError(rawJson: String): String? {
    val candidate = rawJson.trim()
    if (candidate.isBlank()) return null
    return runCatching {
        runtimeJson.parseToJsonElement(candidate).jsonObject
        null
    }.getOrElse { "Enter a valid JSON object." }
}

private fun updateThemeJsonField(
    currentJson: String,
    key: String,
    value: String,
): String {
    val nextValues = (parseJsonObjectOrNull(currentJson)?.toMutableMap() ?: linkedMapOf()).also { values ->
        val normalized = value.trim()
        if (normalized.isBlank()) {
            values.remove(key)
        } else {
            values[key] = JsonPrimitive(normalized)
        }
    }

    if (nextValues.isEmpty()) {
        return ""
    }

    return runtimeJson.encodeToString(JsonObject(nextValues))
}

private fun JsonObject?.themeValue(key: String): String =
    this?.get(key)?.jsonPrimitive?.contentOrNull.orEmpty()

private fun JsonObject?.cssColor(key: String): String? =
    this?.themeValue(key)?.let(::nativeUiColorToCss)

private fun nativeUiColorToCss(rawValue: String): String? {
    val normalized = rawValue.trim().removePrefix("#")
    return when {
        normalized.length == 6 && normalized.matches(Regex("[0-9A-Fa-f]{6}")) -> "#$normalized"
        normalized.length == 8 && normalized.matches(Regex("[0-9A-Fa-f]{8}")) -> {
            val alpha = normalized.substring(0, 2).toIntOrNull(16) ?: return null
            val red = normalized.substring(2, 4).toIntOrNull(16) ?: return null
            val green = normalized.substring(4, 6).toIntOrNull(16) ?: return null
            val blue = normalized.substring(6, 8).toIntOrNull(16) ?: return null
            "rgba($red, $green, $blue, ${alpha.toDouble() / 255.0})"
        }
        else -> null
    }
}

private fun buildConsumerRuntimePreviewModel(rawDocumentJson: String): ConsumerRuntimePreviewModel {
    val jsonObject = parseJsonObjectOrNull(rawDocumentJson)
    val pageObject = jsonObject
        ?.get("pages")
        ?.jsonArray
        ?.firstOrNull()
        ?.jsonObject
    val flattenedBlocks = pageObject
        ?.get("blocks")
        ?.jsonArray
        ?.flatMap(::flattenBlocks)
        .orEmpty()

    val eyebrow = flattenedBlocks.firstText("Label")
        ?: pageObject?.get("title")?.jsonPrimitive?.contentOrNull
        ?: "Home"
    val title = flattenedBlocks.firstText("Title")
        ?: pageObject?.get("title")?.jsonPrimitive?.contentOrNull
        ?: "Consumer Home"
    val body = flattenedBlocks.firstText("Body")
        ?: "Preview the district's NativeUI home content here before saving."
    val buttons = flattenedBlocks.buttonLabels().ifEmpty {
        listOf("Primary Action", "Secondary Action")
    }

    return ConsumerRuntimePreviewModel(
        eyebrow = eyebrow,
        title = title,
        body = body,
        buttons = buttons,
    )
}

private fun flattenBlocks(element: kotlinx.serialization.json.JsonElement): List<JsonObject> {
    val block = runCatching { element.jsonObject }.getOrNull() ?: return emptyList()
    val children = block["blocks"]
        ?.let { childElement ->
            runCatching { childElement.jsonArray.flatMap(::flattenBlocks) }.getOrElse { emptyList() }
        }
        .orEmpty()
    return listOf(block) + children
}

private fun List<JsonObject>.firstText(variant: String): String? =
    firstOrNull { block ->
        block["type"]?.jsonPrimitive?.contentOrNull == "text" &&
            block["variant"]?.jsonPrimitive?.contentOrNull == variant
    }?.get("text")?.jsonPrimitive?.contentOrNull

private fun List<JsonObject>.buttonLabels(): List<String> =
    mapNotNull { block ->
        if (block["type"]?.jsonPrimitive?.contentOrNull == "button") {
            block["label"]?.jsonPrimitive?.contentOrNull
        } else {
            null
        }
    }
