@Composable
fun FieldRow(content: @Composable () -> Unit) {
    Div(
        attrs = {
            style {
                display(org.jetbrains.compose.web.css.DisplayStyle.Flex)
                flexDirection(org.jetbrains.compose.web.css.FlexDirection.Row)
                gap(12.px)
                property("flex-wrap", "wrap")
            }
        }
    ) {
        content()
    }
}

@Composable
fun TextField(
    theme: MaterialThemePalette,
    label: String,
    value: String,
    placeholder: String = "",
    inputType: InputType<String> = InputType.Text,
    inputTypeOverride: String? = null,
    step: String? = null,
    inputPaddingVerticalPx: Int = 14,
    inputPaddingHorizontalPx: Int = 16,
    inputFontSize: String = "0.98rem",
    minHeightPx: Int? = null,
    onValueChange: (String) -> Unit,
) {
    Div(
        attrs = {
            style {
                display(org.jetbrains.compose.web.css.DisplayStyle.Flex)
                flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                gap(6.px)
                flex(1)
                property("min-width", "0")
            }
        }
    ) {
        P(
            attrs = {
                style {
                    margin(0.px)
                    property("color", theme.onSurfaceVariant)
                    property("font-size", "0.78rem")
                    property("font-weight", "700")
                    property("letter-spacing", "0.06em")
                    property("text-transform", "uppercase")
                }
            }
        ) {
            Text(label)
        }
        Input(type = inputType) {
            value(value)
            placeholder(placeholder)
            inputTypeOverride?.let { attr("type", it) }
            step?.let { attr("step", it) }
            onInput { onValueChange(it.value) }
            onChange { onValueChange(it.value) }
            style {
                padding(inputPaddingVerticalPx.px, inputPaddingHorizontalPx.px)
                borderRadius(14.px)
                property("box-sizing", "border-box")
                property("width", "100%")
                minHeightPx?.let { property("min-height", "${it}px") }
                property("background-color", theme.surface)
                property("color", theme.onSurface)
                property("border", "1px solid ${theme.outline}")
                property("box-shadow", "inset 0 1px 0 ${theme.scrim}")
                property("font-size", inputFontSize)
                property("font-weight", "500")
                property("letter-spacing", "-0.01em")
            }
        }
    }
}

@Composable
fun TextAreaField(
    theme: MaterialThemePalette,
    label: String,
    value: String,
    placeholder: String = "",
    rows: Int = 8,
    onValueChange: (String) -> Unit,
) {
    Div(
        attrs = {
            style {
                display(org.jetbrains.compose.web.css.DisplayStyle.Flex)
                flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                gap(6.px)
                flex(1)
                property("min-width", "0")
            }
        }
    ) {
        P(
            attrs = {
                style {
                    margin(0.px)
                    property("color", theme.onSurfaceVariant)
                    property("font-size", "0.78rem")
                    property("font-weight", "700")
                    property("letter-spacing", "0.06em")
                    property("text-transform", "uppercase")
                }
            }
        ) {
            Text(label)
        }
        TextArea(
            value = value,
            attrs = {
                placeholder(placeholder)
                attr("rows", rows.toString())
                onInput { onValueChange(it.value) }
                style {
                    padding(14.px, 16.px)
                    borderRadius(14.px)
                    property("box-sizing", "border-box")
                    property("width", "100%")
                    property("min-height", "180px")
                    property("resize", "vertical")
                    property("background-color", theme.surface)
                    property("color", theme.onSurface)
                    property("border", "1px solid ${theme.outline}")
                    property("box-shadow", "inset 0 1px 0 ${theme.scrim}")
                    property("font-size", "0.94rem")
                    property("font-family", "'SFMono-Regular', 'JetBrains Mono', monospace")
                    property("line-height", "1.5")
                }
            },
        )
    }
}

@Composable
fun ActionButton(
    label: String,
    onClick: () -> Unit,
    theme: MaterialThemePalette,
    isDisabled: Boolean = false,
    isPrimary: Boolean = true,
) {
    var isPressed by remember(isDisabled) { mutableStateOf(false) }

    Button(
        attrs = {
            onClick { onClick() }
            if (isDisabled) disabled()
            onMouseDown { if (!isDisabled) isPressed = true }
            onMouseUp { isPressed = false }
            onMouseLeave { isPressed = false }
            onTouchStart { if (!isDisabled) isPressed = true }
            onTouchEnd { isPressed = false }
            onTouchCancel { isPressed = false }
            onBlur { isPressed = false }
            style {
                padding(12.px, 18.px)
                borderRadius(14.px)
                property("display", "inline-flex")
                property("align-items", "center")
                property("justify-content", "center")
                property("width", "fit-content")
                property("min-width", "120px")
                property("align-self", "flex-start")
                property("cursor", if (isDisabled) "default" else "pointer")
                property("background-color", if (isPrimary) theme.primary else theme.surfaceContainerHighest)
                property("color", if (isPrimary) theme.onPrimary else theme.onSurface)
                property("border", "1px solid ${if (isPrimary) theme.primary else theme.outline}")
                property("font-size", "0.95rem")
                property("font-weight", "700")
                property("letter-spacing", "-0.01em")
                property(
                    "box-shadow",
                    if (isPressed && !isDisabled) {
                        "0 2px 8px ${theme.shadow}"
                    } else {
                        "0 8px 18px ${theme.shadow}"
                    }
                )
                property(
                    "transform",
                    if (isPressed && !isDisabled) "translateY(1px)" else "translateY(0)"
                )
                property("transition", "transform 120ms ease, box-shadow 120ms ease, opacity 120ms ease")
                property("will-change", "transform, box-shadow")
                property("touch-action", "manipulation")
                property("user-select", "none")
                property("-webkit-tap-highlight-color", "transparent")
                if (isDisabled) {
                    property("opacity", "0.65")
                }
            }
        }
    ) {
        Text(label)
    }
}
